import{_ as t,o as a,c as o,ai as i}from"./chunks/framework.DG6aArJf.js";const u=JSON.parse('{"title":"What to Learn Next","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/08_whats-next.md","filePath":"getting-started/08_whats-next.md"}'),r={name:"getting-started/08_whats-next.md"};function n(l,e,s,h,d,c){return a(),o("div",null,[...e[0]||(e[0]=[i('<p><a href="https://github.com/sponsors/giovanni1707" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/Sponsor-%F0%9F%92%96-pink" alt="Sponsor"></a></p><p><a href="https://paypal.me/GiovanniSylvain" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/Sponsor-PayPal-blue?logo=paypal" alt="Sponsor"></a></p><h1 id="what-to-learn-next" tabindex="-1">What to Learn Next <a class="header-anchor" href="#what-to-learn-next" aria-label="Permalink to “What to Learn Next”">​</a></h1><h2 id="you-have-the-foundation" tabindex="-1">You Have the Foundation <a class="header-anchor" href="#you-have-the-foundation" aria-label="Permalink to “You Have the Foundation”">​</a></h2><p>At this point, you understand:</p><ul><li>Why DOM Helpers exists and what problems it addresses</li><li>How the ten modules are organized and what each one is responsible for</li><li>Why modules and sub-modules are kept separate</li><li>The recommended patterns for accessing and updating elements</li><li>How core, enhancers, conditions, storage, and the other modules work together</li><li>What a structured DOM Helpers codebase looks like compared to plain JavaScript</li></ul><p>This is the orientation layer. You know the map before exploring the territory.</p><p>Now it is time to learn each module in depth, starting from the foundation and working outward.</p><hr><h2 id="the-recommended-learning-order" tabindex="-1">The Recommended Learning Order <a class="header-anchor" href="#the-recommended-learning-order" aria-label="Permalink to “The Recommended Learning Order”">​</a></h2><p>Learning in this order ensures that each new concept builds on something you already understand. Skipping ahead is possible, but you may encounter API references to things you have not yet learned.</p><hr><h3 id="step-1-—-the-core-module" tabindex="-1">Step 1 — The Core Module <a class="header-anchor" href="#step-1-—-the-core-module" aria-label="Permalink to “Step 1 — The Core Module”">​</a></h3><p>Start here. Everything else in DOM Helpers connects back to the core.</p><p>The core introduces the three helpers — Elements, Collections, Selector — and the <code>.update()</code> method that every element carries. Once you understand these, you understand the fundamental pattern that runs through the entire library.</p><p><strong>Start with:</strong></p><ul><li><a href="./../01_core/01_what-is-dh-core.html">Introduction to DOM Helpers Core</a> — what the core provides and how the three helpers differ</li><li><a href="./../01_core/02_elements-helper.html">Elements Helper</a> — ID-based element access, caching, and all Elements methods</li><li><a href="./../01_core/03_collections-helper.html">Collections Helper</a> — group access by class, tag, and name; collection methods</li><li><a href="./../01_core/04_selector-helper.html">Selector Helper</a> — CSS selector access for complex queries</li><li><a href="./../01_core/05_the-update-method.html">The Update Method</a> — all 13 update types, change detection, chaining</li><li><a href="./../01_core/07_create-elements.html">Create Elements</a> — <code>createElement</code> and <code>createElement.bulk()</code> for building DOM programmatically</li></ul><hr><h3 id="step-2-—-deep-dive-access-guides" tabindex="-1">Step 2 — Deep-Dive Access Guides <a class="header-anchor" href="#step-2-—-deep-dive-access-guides" aria-label="Permalink to “Step 2 — Deep-Dive Access Guides”">​</a></h3><p>After the core overview, the access guides cover each helper in exhaustive detail. These are reference-level documentation organized by specific method or pattern.</p><p><strong>Elements access:</strong></p><ul><li><a href="./../07_Elements_Access_Methods/01_introduction-to-elements-access.html">Introduction to Elements Access</a></li><li><a href="./../07_Elements_Access_Methods/02_basic-elements-id-usage.html">Basic ID Usage</a></li><li><a href="./../07_Elements_Access_Methods/03_safe-access-methods.html">Safe Access Methods</a> — <code>exists()</code>, <code>get()</code>, <code>getRequired()</code></li><li><a href="./../07_Elements_Access_Methods/04_cache-methods.html">Cache Methods</a></li><li><a href="./../07_Elements_Access_Methods/05_batch-access-methods.html">Batch Access</a></li><li><a href="./../07_Elements_Access_Methods/07_async-waiting.html">Async Waiting</a> — <code>waitFor()</code></li><li><a href="./../07_Elements_Access_Methods/09_property-and-attribute-methods.html">Property and Attribute Methods</a></li></ul><p><strong>Collections access:</strong></p><ul><li><a href="./../08_Collections_Access_Methods/01_introduction-to-collections.html">Introduction to Collections</a></li><li><a href="./../08_Collections_Access_Methods/02_basic-access-methods.html">Basic Access Methods</a></li><li><a href="./../08_Collections_Access_Methods/03_array-like-methods.html">Array-Like Methods</a> — <code>forEach</code>, <code>map</code>, <code>filter</code>, <code>find</code>, <code>reduce</code></li><li><a href="./../08_Collections_Access_Methods/04_dom-manipulation-methods.html">DOM Manipulation Methods</a> — <code>addClass</code>, <code>setStyle</code>, <code>on</code>, <code>off</code></li><li><a href="./../08_Collections_Access_Methods/05_filtering-methods.html">Filtering Methods</a> — <code>visible</code>, <code>hidden</code>, <code>enabled</code>, <code>disabled</code></li></ul><p><strong>Selector access:</strong></p><ul><li><a href="./../09_Selector_Access_Methods/01_introduction-to-selector.html">Introduction to Selector</a></li><li><a href="./../09_Selector_Access_Methods/02_basic-query-methods.html">Basic Query Methods</a></li><li><a href="./../09_Selector_Access_Methods/03_scoped-query-methods.html">Scoped Query Methods</a></li><li><a href="./../09_Selector_Access_Methods/05_async-methods.html">Async Methods</a> — <code>waitFor</code>, <code>waitForAll</code></li></ul><hr><h3 id="step-3-—-the-update-method-in-depth" tabindex="-1">Step 3 — The Update Method in Depth <a class="header-anchor" href="#step-3-—-the-update-method-in-depth" aria-label="Permalink to “Step 3 — The Update Method in Depth”">​</a></h3><p>The <code>.update()</code> method is central to how DOM Helpers works. After you understand the core, study the full update method guide to learn every update type and when to use each one.</p><ul><li><a href="./../10_Update Method Guide/01_what-is-update-and-why.html">What Is Update and Why</a></li><li><a href="./../10_Update Method Guide/02_the-update-object-explained.html">The Update Object Explained</a></li><li><a href="./../10_Update Method Guide/04_update-properties-deep-dive.html">Update Properties Deep Dive</a></li><li><a href="./../10_Update Method Guide/05_fine-grained-updates-change-detection.html">Fine-Grained Change Detection</a></li></ul><p><strong>Multi-element updaters:</strong></p><ul><li><a href="./../11_Elements_Update/01_what-is-elements.update.html">What Is Elements.update</a></li><li><a href="./../12_Collections_Update/01_what-is-collections.update.html">What Is Collections.update</a></li><li><a href="./../13_Selector_Update/01_what-is-selector.update.html">What Is Selector.update</a></li></ul><hr><h3 id="step-4-—-enhancers" tabindex="-1">Step 4 — Enhancers <a class="header-anchor" href="#step-4-—-enhancers" aria-label="Permalink to “Step 4 — Enhancers”">​</a></h3><p>Once you are comfortable with the core, enhancers will feel natural. They all follow the same patterns you already know — they just make common operations shorter.</p><p>Learn them in the order that matches how you use the library:</p><p><strong>Shortcuts for quicker access:</strong></p><ul><li><a href="./../02_enhancers/20_Id_Shortcut/01_introduction-to-id-shortcut.html">Id Shortcut</a> — the <code>Id()</code> function</li><li><a href="./../02_enhancers/13_Collection_Shortcuts/01_introduction-to-collection-shortcuts.html">Collection Shortcuts</a> — <code>ClassName</code>, <code>TagName</code>, <code>Name</code></li><li><a href="./../02_enhancers/14_Global_Query/01_introduction-to-global-query.html">Global Query</a> — <code>querySelector()</code>, <code>querySelectorAll()</code> (also available as <code>query()</code>, <code>queryAll()</code>)</li></ul><p><strong>Updaters for more concise updates:</strong></p><ul><li><a href="./../02_enhancers/12_Bulk_Property_Updaters/01_introduction-to-bulk-property-updaters.html">Bulk Property Updaters</a> — <code>Elements.textContent()</code>, <code>Elements.style()</code>, etc.</li><li><a href="./../02_enhancers/15_Indexed_Collection_Updates/01_introduction-to-indexed-collection-updates.html">Indexed Collection Updates</a></li><li><a href="./../02_enhancers/21_Array_Based_Updates/01_introduction-to-array-based-updates.html">Array-Based Updates</a></li></ul><hr><h3 id="step-5-—-reactive" tabindex="-1">Step 5 — Reactive <a class="header-anchor" href="#step-5-—-reactive" aria-label="Permalink to “Step 5 — Reactive”">​</a></h3><p>The reactive module introduces state management with automatic propagation. When state changes, effects re-run, computed values update, and the DOM reflects the new state — all without any manual calls.</p><p>Always use the shortcut form — <code>state()</code>, <code>effect()</code>, <code>computed()</code>, <code>watch()</code>, <code>batch()</code>, <code>ref()</code>, <code>refs()</code> — not the <code>ReactiveUtils.</code> prefix.</p><p><strong>Start with the overview:</strong></p><ul><li><a href="./09_reactive.html">Reactive (Getting Started)</a> — shortcuts, core functions, and how reactive connects to core, conditions, and storage</li></ul><p><strong>Then the full documentation:</strong></p><ul><li><a href="./../04_reactive/31_Reactive_State/01_what-is-reactive-state.html">What Is Reactive State</a></li><li><a href="./../04_reactive/39_Reactive_Utils_Shortcut/01_what-is-the-standalone-api.html">Reactive Utils Shortcut</a> — the complete shortcut API</li><li><a href="./../04_reactive/40_Reactive_Guide/01_reactive_introduction.html">Reactive Guide</a> — full walkthrough from basics to advanced</li><li><a href="./../04_reactive/40_Reactive_Guide/11_reactive_with_dom_helpers_core.html">Reactive with DOM Helpers Core</a></li><li><a href="./../04_reactive/40_Reactive_Guide/13_reactive_with_conditions.html">Reactive with Conditions</a></li></ul><hr><h3 id="step-6-—-conditions" tabindex="-1">Step 6 — Conditions <a class="header-anchor" href="#step-6-—-conditions" aria-label="Permalink to “Step 6 — Conditions”">​</a></h3><p>After you are fluent in accessing and updating elements, Conditions introduces the next structural level: instead of writing update calls in event handlers, you declare what the DOM should look like for each state.</p><ul><li><a href="./../03_conditions/Conditions_Guide/01_what-is-conditions.html">What Is Conditions</a></li><li><a href="./../03_conditions/Conditions_Guide/02_whenState-syntax-and-basic-usage.html">WhenState Syntax and Basic Usage</a></li><li><a href="./../03_conditions/Conditions_Guide/03_condition-matchers.html">Condition Matchers</a></li><li><a href="./../03_conditions/Conditions_Guide/04_property-handlers.html">Property Handlers</a></li><li><a href="./../03_conditions/Conditions_Guide/05_apply-and-watch.html">Apply and Watch</a></li></ul><hr><h3 id="step-7-—-storage" tabindex="-1">Step 7 — Storage <a class="header-anchor" href="#step-7-—-storage" aria-label="Permalink to “Step 7 — Storage”">​</a></h3><p>StorageUtils can be learned at any point. It does not depend on the core, reactive, or conditions — it is a standalone utility. But understanding it after the core and reactive lets you see immediately how it connects: storage holds persisted state, reactive state holds the live version, and watchers keep them in sync.</p><ul><li><a href="./../05_storageUtils/01_introduction-to-storage-utils.html">Introduction to StorageUtils</a></li><li><a href="./../05_storageUtils/02_save-and-load.html">Save and Load</a></li><li><a href="./../05_storageUtils/04_namespaces.html">Namespaces</a></li><li><a href="./../05_storageUtils/05_watch-cross-tab-sync.html">Watch and Cross-Tab Sync</a></li><li><a href="./../05_storageUtils/06_create-auto-save.html">Auto-Save</a></li></ul><hr><h3 id="step-8-—-createelement" tabindex="-1">Step 8 — createElement <a class="header-anchor" href="#step-8-—-createelement" aria-label="Permalink to “Step 8 — createElement”">​</a></h3><p><code>createElement</code> and <code>createElement.bulk()</code> are used when you need to build DOM elements from scratch in JavaScript. They are not required for working with existing HTML, but they are essential for dynamic UIs that create elements on demand.</p><ul><li><a href="./../06_createElement/01_what-is-createElement.html">What Is createElement</a></li><li><a href="./../06_createElement/02_enhanced-createElement.html">Enhanced createElement</a></li><li><a href="./../06_createElement/03_bulk-element-creation.html">Bulk Element Creation</a></li><li><a href="./../06_createElement/04_bulk-result-methods.html">Bulk Result Methods</a></li><li><a href="./../06_createElement/05_configuration-object.html">Configuration Object</a></li></ul><hr><h3 id="step-9-—-native-enhance" tabindex="-1">Step 9 — Native Enhance <a class="header-anchor" href="#step-9-—-native-enhance" aria-label="Permalink to “Step 9 — Native Enhance”">​</a></h3><p>The native-enhance module is ideal if you have an existing project that already uses <code>document.getElementById</code>, <code>document.getElementsByClassName</code>, or <code>querySelector</code>. Load it and those calls automatically return elements with full DOM Helpers power — no refactoring required.</p><ul><li><a href="./../native-enhance/01_what-is-native-enhance.html">What Is Native Enhance</a></li></ul><hr><h3 id="step-10-—-dom-form" tabindex="-1">Step 10 — DOM Form <a class="header-anchor" href="#step-10-—-dom-form" aria-label="Permalink to “Step 10 — DOM Form”">​</a></h3><p>The DOM Form module (<code>Forms</code>) gives every form a structured API for reading values, validating fields, and submitting data. Learn this when your project involves forms that go beyond a simple one-off submission.</p><ul><li><a href="./../dom-form/01_what-is-dom-form.html">What Is DOM Form</a></li></ul><hr><h3 id="step-11-—-animation" tabindex="-1">Step 11 — Animation <a class="header-anchor" href="#step-11-—-animation" aria-label="Permalink to “Step 11 — Animation”">​</a></h3><p>The animation module extends every element and collection returned by the core with <code>fadeIn</code>, <code>fadeOut</code>, <code>slideUp</code>, <code>slideDown</code>, <code>transform</code>, and a chainable <code>.animate()</code> builder. All animations are promises — you can <code>await</code> them.</p><ul><li><a href="./../animation/01_what-is-animation.html">What Is Animation</a></li></ul><hr><h3 id="step-12-—-async" tabindex="-1">Step 12 — Async <a class="header-anchor" href="#step-12-—-async" aria-label="Permalink to “Step 12 — Async”">​</a></h3><p><code>AsyncHelpers</code> covers the async utility patterns that appear in nearly every project: debounce, throttle, fetch with timeout and retry, sleep, parallel execution, and async event handler wrappers.</p><ul><li><a href="./../async/01_what-is-async.html">What Is AsyncHelpers</a></li></ul><hr><h3 id="step-13-—-spa-router" tabindex="-1">Step 13 — SPA Router <a class="header-anchor" href="#step-13-—-spa-router" aria-label="Permalink to “Step 13 — SPA Router”">​</a></h3><p>The SPA Router is the most complete module in the library. It handles client-side navigation, view mounting from <code>&lt;template&gt;</code> elements, animated transitions, declarative links, and navigation guards — all without a page reload.</p><ul><li><a href="./../10_spa/01_what-is-spa-router.html">What Is SPA Router</a></li><li><a href="./../10_spa/02_getting-started.html">Getting Started with the Router</a></li><li><a href="./../10_spa/03_defining-routes.html">Defining Routes</a></li><li><a href="./../10_spa/04_navigation.html">Navigation</a></li><li><a href="./../10_spa/05_route-params-and-query.html">Route Params and Query</a></li><li><a href="./../10_spa/06_view-transitions.html">View Transitions</a></li><li><a href="./../10_spa/07_router-links.html">Router Links</a></li><li><a href="./../10_spa/08_navigation-guards.html">Navigation Guards</a></li><li><a href="./../10_spa/09_real-world-examples.html">Real-World Examples</a></li><li><a href="./../10_spa/10_api-reference.html">API Reference</a></li></ul><hr><h2 id="a-note-on-learning-pace" tabindex="-1">A Note on Learning Pace <a class="header-anchor" href="#a-note-on-learning-pace" aria-label="Permalink to “A Note on Learning Pace”">​</a></h2><p>There is no requirement to learn everything before you start building. The core module alone — Elements, Collections, Selector, and <code>.update()</code> — is enough to build real, structured pages. Add enhancers when repetition appears. Add reactive when you need state that automatically propagates changes. Add Conditions when state-driven UI mapping gets complex. Add Storage when persistence is needed. Add DOM Form, Animation, Async, and the Router as your project&#39;s requirements grow.</p><p>The library is layered intentionally so you can adopt it at your own pace without hitting walls.</p><hr><h2 id="begin-here" tabindex="-1">Begin Here <a class="header-anchor" href="#begin-here" aria-label="Permalink to “Begin Here”">​</a></h2><p>If you have not started yet, the first place to go is the core module introduction:</p><ul><li><strong><a href="./../01_core/01_what-is-dh-core.html">What Is DOM Helpers Core</a></strong></li></ul>',88)])])}const m=t(r,[["render",n]]);export{u as __pageData,m as default};
